external_knowledge:
- 'power-hungry nature' refers to products with high energy consumption;
- The term 'top candidates' is used metaphorically to indicate the products with the highest energy consumption per category, limited to the top three within each category;
- The 'category's average energy consumption' is the average energy consumption per time unit of all products within the same category.

sql:
SELECT AVG(energy_per_time) AS average_energy_consumption
FROM products
WHERE certification_status = 'certified';

SELECT AVG(energy_per_time) AS average_energy_per_time
FROM products
WHERE category IN ('A', 'B');

SELECT product_id, brand, model_name, energy_per_time, units
FROM products
ORDER BY energy_per_time DESC;

SELECT AVG(energy_per_time) AS average_energy_consumption
FROM products
WHERE category = 'A' AND submission_date BETWEEN '2020-01-01' AND '2023-12-31';

SELECT AVG(energy_per_time) AS average_energy_consumption
FROM products
WHERE product_type = 'Notebook';
